package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithHeaderComments() {
        // Given
        Object[] headerComments = {"Comment 1", "Comment 2"};
        char delimiter = ',';
        char quoteCharacter = '"';
        QuoteMode quoteMode = QuoteMode.ALL_NON_NULL;
        Character commentMarker = '#';
        Character escapeCharacter = '\\';
        boolean ignoreSurroundingSpaces = true;
        boolean ignoreEmptyLines = false;
        String recordSeparator = "\r\n";
        String nullString = "NULL";
        String[] header = {"Header1", "Header2"};
        boolean skipHeaderRecord = true;
        boolean allowMissingColumnNames = false;
        boolean ignoreHeaderCase = true;
        boolean trim = true;
        boolean trailingDelimiter = false;

        CSVFormat csvFormat = new CSVFormat(delimiter, quoteCharacter, quoteMode, commentMarker, escapeCharacter,
                ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, headerComments, header,
                skipHeaderRecord, allowMissingColumnNames, ignoreHeaderCase, trim, trailingDelimiter);

        CSVFormat expectedFormat = new CSVFormat(delimiter, quoteCharacter, quoteMode, commentMarker, escapeCharacter,
                ignoreSurroundingSpaces, ignoreEmptyLines, recordSeparator, nullString, headerComments, header,
                skipHeaderRecord, allowMissingColumnNames, ignoreHeaderCase, trim, trailingDelimiter);

        // When
        CSVFormat result = csvFormat.withHeaderComments(headerComments);

        // Then
        assertEquals(expectedFormat, result);
    }
}
